init_eqs:
n = -10000; loop (20000, megabuf(n)=0; gmegabuf(n)=0; n +=1; );

MINBPM = 35; MAXBPM = 210; num_res = 400;
index = 0;
loop (num_res,
n = index*8;
BPM      = minbpm * pow(maxbpm/minbpm,index/(num_res-1));
megabuf(n) = BPM;
index += 1;
);

exc_2=0.2; maxquad=1;

//structure of resonator data, starting at megabuf (0)
//size = 8
//0: BPM
//1: v
//2: y
//3: amplitude
//4: amplitude after harmonics post processing
//5: beatcos
//6: beatsin


pi = 3.1416;

frame_eqs:
dt = min (1/fps,0.1) ; //Stability !
dec_m = 1 - 4*dt; dec_s = 1 - 1.25*dt;
vol =  (bass+mid+treb);

vol_ = vol_*dec_m + (1-dec_m)*vol; exc = vol-vol_;
excite = atan (exc*2)/1.6;

index=0; ratio = log(maxbpm/minbpm); sum_res = 0.01; maxquad = 0.2;
loop (num_res,
n = index*8;
omega      =   megabuf(n) * 6.2832/60;
megabuf (n+1) *= 1-0.2*dt; //damping
EC_Steps = int (10*omega*dt)+1;
loop (EC_Steps, // Euler-Cauchy steps
megabuf (n+1) += (excite - sqr(omega)*megabuf(n + 2)) * dt/EC_Steps;
megabuf (n+2) += megabuf(n+1) * dt/EC_Steps);
beatcos  = megabuf(n+1);
beatsin = megabuf(n+2)*omega; //2pi/60
quad     = sqrt (pow(beatsin,2) + pow(beatcos,2)) ;
if (maxquad < quad, maxquad = quad, 0);
megabuf (n+3) = megabuf(n+3) *dec_s +  quad* (1-dec_s);
megabuf (n+4) = megabuf(n+3);
megabuf (n+5) = beatcos;
megabuf (n+6) = beatsin ;

sum_res += megabuf (n+3);
index += 1;
);

n = 0;
loop (num_res,
//  scale = sqrt (megabuf(n+3));
scale = 1;
gmegabuf(n+5) = megabuf(n+5) * scale;
gmegabuf(n+6) = megabuf(n+6) * scale;
n+=8;);

n = 0; imax = 0;
loop (num_res,
q12 += megabuf(n*8+1);
q13 += megabuf(n*8+2);
n+=1;);


maxquad_ = maxquad_*dec_s + (1-dec_s)*maxquad;
q1 = sqrt(0.7/maxquad_);
tr2 += maxquad/fps;
q2 = tr2/200; //vert. mov. muster

q3 = 0.03; //scale x-shift shapes

monitor = q1;

q32 = aspecty;

shape_0_per_frame:
sample = instance/num_inst;

x = sample; y = 0.75;
r = .7; g = 0; b = 0;
r2 = r*0.3; g2 = g*0.3; b2 = 0;
a = 1;
a2 = 1;

shape_1_per_frame:
sample = instance/num_inst;

x = sample; y = 0.25;
r = .7; g = 0; b = 0;
r2 = r*0.3; g2 = g*0.3; b2 = 0;
a = 1;
a2 = 1;

shape_2_per_frame:
sample = instance/num_inst;


rx1 = gmegabuf (instance*8+5);
rx2 = gmegabuf ((num_inst-instance-1)*8+5); //mirrored

ry1 = gmegabuf (instance*8+6);
ry2 = gmegabuf ((num_inst-instance-1)*8+6);//mirrored

kx = 0.07* q1;
ky = 0.15 * q1;


x0 = (rx1 - rx2)*kx + q13*q3 * (abs(sample-0.5)-0.25);;

cx = 0.7 ;
x = x0+(1-cx)/2 + cx*sample;


y0 = (ry1+ry2)*ky + 0*q13*(abs(sample-0.5)-0.3);
y = y0+0.75;

r = 1; g = 1; b = 1;
r2 = r*0.2; g2 = g*0.3; b2 = 0;
a = 1;
a2 = 1;

rad = q32*0.025;

ang = atan2 (x0,y0);

shape_3_per_frame:
sample = instance/num_inst;


rx1 = gmegabuf (instance*8+6);
rx2 = gmegabuf ((num_inst-instance-1)*8+6); //mirrored

ry1 = gmegabuf (instance*8+5);
ry2 = gmegabuf ((num_inst-instance-1)*8+5);//mirrored

kx = 0.07* q1;
ky = 0.15 *q1;


x0 = (rx1 - rx2)*kx - q13*q3 * (abs(sample-0.5)-0.25);;

cx = 0.7 ;
x = x0+(1-cx)/2 + cx*sample;


y0 = (ry1+ry2)*ky + 0*q13*(abs(sample-0.5)-0.3) ;
y = y0+0.25;

r = 1; g = 1; b = 1;
r2 = r*0.2; g2 = g*0.3; b2 = 0;
a = 1;
a2 = 1;

rad = q32*0.025;

ang = atan2 (x0,y0);
